AUI.add(
	'liferay-session',
	(A) => {
		const Lang = A.Lang;

		const BUFFER_TIME = [];

		const CONFIG = A.config;

		const DOC = CONFIG.doc;

		const MAP_SESSION_STATE_EVENTS = {
			active: 'activated',
		};

		const SESSION_STATE_CHECK_INTERVAL = 1000;

		const SRC = {};

		const SRC_EVENT_OBJ = {
			src: SRC,
		};

		const TOAST_ID = 'sessionToast';

		const URL_BASE = themeDisplay.getPathMain() + '/portal/';

		const SessionBase = A.Component.create({
			ATTRS: {
				autoExtend: {
					value: false,
				},
				redirectOnExpire: {
					value: true,
				},
				redirectUrl: {
					value: '',
				},
				sessionLength: {
					getter: '_getLengthInMillis',
					value: 0,
				},
				sessionState: {
					value: 'active',
				},
				sessionTimeoutOffset: {
					getter: '_getLengthInMillis',
					value: 0,
				},
				timestamp: {
					getter: '_getTimestamp',
					setter: '_setTimestamp',
					value: 0,
				},
				warningLength: {
					getter: '_getLengthInMillis',
					setter: '_setWarningLength',
					value: 0,
				},
				warningTime: {
					getter: '_getWarningTime',
					value: 0,
				},
			},
			EXTENDS: A.Base,
			NAME: 'liferaysession',
			prototype: {
				_afterSessionStateChange(event) {
					const instance = this;

					const details = event.details;
					const newVal = event.newVal;

					let src = null;

					if ('src' in event && details.length) {
						src = details[0];
					}

					instance.fire(
						MAP_SESSION_STATE_EVENTS[newVal] || newVal,
						src
					);
				},

				_defActivatedFn(event) {
					const instance = this;

					instance.set('timestamp');

					if (event.src === SRC) {
						Liferay.Util.fetch(URL_BASE + 'extend_session').then(
							(response) => {
								if (response.status === 500) {
									instance.expire();
								}
							}
						);
					}
				},

				_defExpiredFn(event) {
					const instance = this;

					A.clearInterval(instance._intervalId);

					if (event.src === SRC) {
						instance._expireSession();
					}
				},

				_expireSession() {
					const instance = this;

					Liferay.Util.fetch(URL_BASE + 'expire_session').then(
						(response) => {
							if (response.ok) {
								Liferay.fire('sessionExpired');

								if (instance.get('redirectOnExpire')) {
									location.href = instance.get('redirectUrl');
								}
							}
							else {
								A.setTimeout(() => {
									instance._expireSession();
								}, 1000);
							}
						}
					);
				},

				_getLengthInMillis(value) {
					return value * 1000;
				},

				_getTimestamp() {
					const instance = this;

					return (
						Liferay.Util.Cookie.get(
							instance._cookieKey,
							Liferay.Util.Cookie.TYPES.NECESSARY
						) || instance._initTimestamp
					);
				},

				_getWarningTime() {
					const instance = this;

					return (
						instance.get('sessionLength') -
						instance.get('warningLength')
					);
				},

				_initEvents() {
					const instance = this;

					instance.publish('activated', {
						defaultFn: A.bind('_defActivatedFn', instance),
					});

					instance.publish('expired', {
						defaultFn: A.bind('_defExpiredFn', instance),
					});

					instance.publish('warned');

					instance._eventHandlers = [
						instance.on(
							'sessionStateChange',
							instance._onSessionStateChange
						),
						instance.after(
							'sessionStateChange',
							instance._afterSessionStateChange
						),
						A.on('io:complete', (transactionId, response, args) => {
							if (
								!args ||
								(args && args.sessionExtend) ||
								!Lang.isBoolean(args.sessionExtend)
							) {
								instance.resetInterval();
							}
						}),
						Liferay.once('screenLoad', () => {
							instance.destroy();
						}),
					];
				},

				_onSessionStateChange(event) {
					const instance = this;

					const newVal = event.newVal;
					const prevVal = event.prevVal;

					if (prevVal === 'expired' && prevVal !== newVal) {
						event.preventDefault();
					}
					else if (prevVal === 'active' && prevVal === newVal) {
						instance._afterSessionStateChange(event);
					}
				},

				_setTimestamp(value) {
					const instance = this;

					value = String(value || Date.now());

					instance._initTimestamp = value;

